import { FetchFunction } from '@ai-sdk/provider-utils';
import { createTestServer } from '@ai-sdk/test-server/with-vitest';
import { describe, expect, it } from 'vitest';
import { PixelArtImageModel } from './pixelart-image-model';

const prompt = 'A pixel art hero wielding a sword';

const TEST_BASE_URL = 'https://api.example.com/v1';
const GENERATE_URL = `${TEST_BASE_URL}/images/generate`;

// Minimal valid base64 1×1 PNG
const FAKE_B64 = 'iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==';

const DEFAULT_RESPONSE = {
  created: 1712000000,
  data: [{ b64_json: FAKE_B64, revised_prompt: null }],
};

function createBasicModel({
  headers,
  fetch,
  currentDate,
}: {
  headers?: Record<string, string | undefined>;
  fetch?: FetchFunction;
  currentDate?: () => Date;
} = {}) {
  return new PixelArtImageModel('pixelart-v1', {
    provider: 'pixelart.image',
    baseURL: TEST_BASE_URL,
    headers: headers ?? { Authorization: 'Bearer test-key' },
    fetch,
    _internal: { currentDate },
  });
}

describe('PixelArtImageModel', () => {
  const server = createTestServer({
    [GENERATE_URL]: {
      response: {
        type: 'json-value',
        body: DEFAULT_RESPONSE,
      },
    },
  });

  // ── constructor ──────────────────────────────────────────────────────────
  describe('constructor', () => {
    it('exposes correct provider and model information', () => {
      const model = createBasicModel();
      expect(model.provider).toBe('pixelart.image');
      expect(model.modelId).toBe('pixelart-v1');
      expect(model.specificationVersion).toBe('v3');
      expect(model.maxImagesPerCall).toBe(4);
    });
  });

  // ── doGenerate – request body ────────────────────────────────────────────
  describe('doGenerate – request body', () => {
    it('sends prompt, n, and model id', async () => {
      await createBasicModel().doGenerate({
        prompt,
        n: 2,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        files: undefined,
        mask: undefined,
        providerOptions: {},
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: 'pixelart-v1',
        prompt,
        n: 2,
      });
    });

    it('includes size when provided', async () => {
      await createBasicModel().doGenerate({
        prompt,
        n: 1,
        size: '512x512',
        aspectRatio: undefined,
        seed: undefined,
        files: undefined,
        mask: undefined,
        providerOptions: {},
      });

      expect(await server.calls[0].requestBodyJson).toMatchObject({
        size: '512x512',
      });
    });

    it('omits size when not provided', async () => {
      await createBasicModel().doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        files: undefined,
        mask: undefined,
        providerOptions: {},
      });

      const body = await server.calls[0].requestBodyJson;
      expect(body).not.toHaveProperty('size');
    });

    it('sends style provider option as-is', async () => {
      await createBasicModel().doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        files: undefined,
        mask: undefined,
        providerOptions: { pixelart: { style: 'retro' } },
      });

      expect(await server.calls[0].requestBodyJson).toMatchObject({
        style: 'retro',
      });
    });

    it('sends pixelDensity as pixel_density', async () => {
      await createBasicModel().doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        files: undefined,
        mask: undefined,
        providerOptions: { pixelart: { pixelDensity: 16 } },
      });

      expect(await server.calls[0].requestBodyJson).toMatchObject({
        pixel_density: 16,
      });
    });

    it('sends both style and pixelDensity together', async () => {
      await createBasicModel().doGenerate({
        prompt,
        n: 1,
        size: '1024x1024',
        aspectRatio: undefined,
        seed: undefined,
        files: undefined,
        mask: undefined,
        providerOptions: { pixelart: { style: '8bit', pixelDensity: 4 } },
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: 'pixelart-v1',
        prompt,
        n: 1,
        size: '1024x1024',
        style: '8bit',
        pixel_density: 4,
      });
    });
  });

  // ── doGenerate – headers ─────────────────────────────────────────────────
  describe('doGenerate – headers', () => {
    it('forwards provider-level headers', async () => {
      const model = createBasicModel({
        headers: { 'X-Custom-Provider': 'provider-value' },
      });

      await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        files: undefined,
        mask: undefined,
        providerOptions: {},
      });

      expect(server.calls[0].requestHeaders).toMatchObject({
        'x-custom-provider': 'provider-value',
      });
    });

    it('merges request-level headers with provider headers', async () => {
      const model = createBasicModel({
        headers: { 'X-Provider': 'prov' },
      });

      await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        files: undefined,
        mask: undefined,
        providerOptions: {},
        headers: { 'X-Request': 'req' },
      });

      expect(server.calls[0].requestHeaders).toMatchObject({
        'x-provider': 'prov',
        'x-request': 'req',
      });
    });
  });

  // ── doGenerate – response ────────────────────────────────────────────────
  describe('doGenerate – response', () => {
    it('returns base64 images from data array', async () => {
      server.urls[GENERATE_URL].response = {
        type: 'json-value',
        body: {
          created: 1712000000,
          data: [
            { b64_json: FAKE_B64, revised_prompt: null },
            { b64_json: FAKE_B64, revised_prompt: null },
          ],
        },
      };

      const result = await createBasicModel().doGenerate({
        prompt,
        n: 2,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        files: undefined,
        mask: undefined,
        providerOptions: {},
      });

      expect(result.images).toHaveLength(2);
      expect(result.images[0]).toBe(FAKE_B64);
      expect(result.images[1]).toBe(FAKE_B64);
    });

    it('includes timestamp and modelId in response metadata', async () => {
      const testDate = new Date('2024-06-01T00:00:00Z');
      const model = createBasicModel({ currentDate: () => testDate });

      const result = await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        files: undefined,
        mask: undefined,
        providerOptions: {},
      });

      expect(result.response).toStrictEqual({
        timestamp: testDate,
        modelId: 'pixelart-v1',
        headers: expect.any(Object),
      });
    });

    it('exposes created and image metadata via providerMetadata', async () => {
      server.urls[GENERATE_URL].response = {
        type: 'json-value',
        body: {
          created: 1712345678,
          data: [{ b64_json: FAKE_B64, revised_prompt: 'A revised prompt' }],
        },
      };

      const result = await createBasicModel().doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        files: undefined,
        mask: undefined,
